public String plusOut(String str, String word) {
    StringBuilder sb = new StringBuilder();
    int wordLength = word.length();
    int i = 0;
    while (i < str.length()) {
        int j = 0;
        while (j < wordLength && i + j < str.length() && str.charAt(i + j) == word.charAt(j)) {
            j++;
        }
        if (j == wordLength) {
            sb.append(word);
            i += j;
        } else {
