private void swap(int[] nums, int i, int j) {
    int temp = nums[i];
    nums[i] = nums[j];
    nums[j] = temp;
}

public String atFirst(String str) {
    if (str.length() < 1) return "@@";
    if (str.length() < 2) return str + "@";
    return str.substring(0, 2);
}

