public boolean evenlySpaced(int a, int b, int c) {
    int[] numbers = {a, b, c};
    Arrays.sort(numbers);
    int smallest = numbers[0];
    int middle = numbers[1];
    int largest = numbers[2];
    if (middle - smallest == largest - middle) {
        return true;
    } else {
        return false;
    }
}

